const arr = ["Apple", "Banana", "Pear"];

// Imperative for-loop
for (let i = 0; i < arr.length; i++) {
 console.log(arr[i]);
}

// Declarative for-loop
arr.forEach(
 (s) => console.log(s)
);

// The end condition will cause an array out of bounds error
for (let i = 0; i <= arr.length; i++) {
 console.log(arr[i]);
}

const arr = [43, 57, 87, 94, 23, 87];

// Imperative
for (let i = 0; i < arr.length - 1; i++) {
 console.log(arr[i] + arr[i+1]);
}

const arr = [43, 57, 87, 94, 23, 87];

// The bounds and management of the state of i is up to you!
for (let i = 0; i < arr.length; i++) {
 // Some code...
}

// You can even set i to an invalid value and break the program!
for (let i = 0; i < arr.length; i++) {
 i = -1;
 console.log(arr[i]);
}

// This gives the developer less trust so now they can't break it if they tried.
arr.forEach(
 (s) => console.log(s)
);

const num1 = 252;
const num2 = 105;

let a = Math.abs(num1);
let b = Math.abs(num2);

// Calculate GCD
while (a > 0 && b > 0 && a != b) {
 if (a > b) {
  a-=b;
 }
 else {
  b-=a;
 }
}

const GCD = a || b;

// in index.js
import findGCD from "./utils.js";

const num1 = 252;
const num2 = 105;
const GCD = findGCD(num1, num2);

// in utils.js file
export default function findGCD(num1, num2) {
   let a = Math.abs(num1);
   let b = Math.abs(num2);
   while (a > 0 && b > 0 && a !== b) {
      if(a > b){
         a-=b;
      }else{
         b-=a;
      };
   };
   return a || b;
}
